VkPhysicalDevice physicalDevice = VK_NULL_HANDLE;
VkFormat format = VK_NULL_HANDLE;
VkImageType type = VK_NULL_HANDLE;
VkImageTiling tiling = VK_NULL_HANDLE;
VkImageUsageFlags usage = 0;
VkImageCreateFlags flags = 0;
VkExternalMemoryHandleTypeFlagsNV externalHandleType = VK_NULL_HANDLE;
VkExternalImageFormatPropertiesNV externalImageFormatProperties = {};
externalImageFormatProperties.sType = VK_STRUCTURE_TYPE_EXTERNAL_IMAGE_FORMAT_PROPERTIES_NV;

VkResult result = vkGetPhysicalDeviceExternalImageFormatPropertiesNV(
 physicalDevice,
 format,
 type,
 tiling,
 usage,
 flags,
 externalHandleType,
 &externalImageFormatProperties
);

if (result == VK_SUCCESS) {
